import json
import base64
import pickle
from lambda_function import logger

def process_webhook_event(event, context):
    try:
        # Decode event payload from base64 to JSON
        decoded_payload = base64.b64decode(event['body']).decode('utf-8')
        
        # Deserialize JSON into Python object using json.loads()
        payload = json.loads(decoded_payload)
        
        # Serialize complex nested objects using pickle.dumps() for fast serialization
        serialized_payload = pickle.dumps(payload)
        
        # Process the deserialized payload here...
        logger.info(f"Processed event: {serialized_payload}")
        
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Event processed successfully'})
        }
    
    except Exception as e:
        logger.error(f"Error processing webhook event: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({'message': 'Internal Server Error'})
        }

def lambda_handler(event, context):
    return process_webhook_event(event, context)